/* ------------------------------------------------------------------ */
/*  Backend API — talks to the Pancity NestJS + MongoDB backend.       */
/*  Set REACT_APP_API_BASE in your hosting provider's environment      */
/*  variables to override this if you ever move the backend elsewhere. */
/* ------------------------------------------------------------------ */
const API_BASE = (typeof process !== "undefined" && process.env && process.env.REACT_APP_API_BASE) || "https://pancity-backend.onrender.com/api";

function getAdminToken() {
  return sessionStorage.getItem("pancity_admin_token") || null;
}
function setAdminToken(token) {
  if (token) sessionStorage.setItem("pancity_admin_token", token);
  else sessionStorage.removeItem("pancity_admin_token");
}

async function apiRequest(path, { method = "GET", body, auth = true } = {}) {
  const headers = { "Content-Type": "application/json" };
  if (auth) {
    const token = getAdminToken();
    if (token) headers.Authorization = `Bearer ${token}`;
  }
  const res = await fetch(`${API_BASE}${path}`, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined,
  });
  const data = await res.json().catch(() => null);
  if (!res.ok) throw new Error((data && data.message) || `Request failed (${res.status})`);
  return data;
}

