function genPlans(network, category) {
  const sizes = ["500MB", "1GB", "1.5GB", "2GB", "3GB", "5GB", "10GB"];
  const count = 5 + Math.floor(rand() * 3);
  return Array.from({ length: count }).map((_, i) => {
    const size = sizes[i % sizes.length];
    const buyingPrice = Math.round(150 + rand() * 2500);
    const margin = Math.round(buyingPrice * (0.05 + rand() * 0.15)) + 20;
    const userPrice = buyingPrice + margin;
    const resellerPrice = buyingPrice + Math.round(margin * 0.5);
    const cashback = Math.round(rand() * 25);
    return {
      id: `${network}-${category}-${i + 1}`,
      planId: `${network.slice(0, 3).toUpperCase()}${category.replace(" ", "").slice(0, 2).toUpperCase()}${100 + i}`,
      size,
      validity: i % 5 === 0 ? "24 hours" : i % 3 === 0 ? "7 days" : "30 days",
      buyingPrice,
      userPrice,
      resellerPrice,
      cashback,
      status: rand() < 0.85 ? "active" : "inactive",
      sortOrder: i + 1,
    };
  });
}

const initialNetworkPlans = {};
NETWORKS.forEach((net) => {
  initialNetworkPlans[net.name] = {};
  PLAN_CATEGORIES.forEach((cat) => {
    initialNetworkPlans[net.name][cat] = genPlans(net.name, cat);
  });
});

