function DashboardPage({ onQuickAction }) {
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [typeFilter, setTypeFilter] = useState("all");
  const [page, setPage] = useState(1);
  const pageSize = 8;

  const [stats, setStats] = useState({
    totalUsers: 0, activeUsers: 0, newUsersToday: 0, walletBalance: 0,
    totalTransactions: 0, pendingTransactions: 0, successfulTransactions: 0,
    failedTransactions: 0, todayRevenue: 0, monthlyRevenue: 0,
  });
  const [revenueSeries, setRevenueSeries] = useState([]);
  const [networkSales, setNetworkSales] = useState([]);
  const [recentTx, setRecentTx] = useState([]);

  // Replaces the top-level `stats`, `revenueSeries`, `networkSales` and
  // `transactions` mock arrays/objects with a live fetch from the backend.
  useEffect(() => {
    api.getStats().then(setStats).catch(() => {});
    api.getRevenueSeries(14).then((rows) => {
      setRevenueSeries(rows.map((r) => ({
        label: new Date(r.date).toLocaleDateString("en-NG", { day: "2-digit", month: "short" }),
        revenue: r.revenue,
        payouts: 0, // no separate payout ledger yet — Phase 2
      })));
    }).catch(() => {});
    api.getNetworkSales().then((rows) => {
      setNetworkSales(rows.map((r) => {
        const meta = NETWORKS.find((n) => n.name.toLowerCase() === (r.network || "").toLowerCase());
        return { name: r.network, value: r.revenue, color: meta?.color || "#64748B" };
      }));
    }).catch(() => {});
    api.listTransactions({ limit: pageSize * 5 }).then((res) => {
      setRecentTx((res.items || []).map((t) => ({
        id: t.reference,
        user: t.user?.name || "Unknown",
        type: TYPE_LABELS[t.type] || t.type,
        amount: t.amount,
        status: t.status,
      })));
    }).catch(() => {});
  }, []);

  const filtered = useMemo(() => {
    return recentTx.filter((t) => {
      const matchesSearch =
        t.id.toLowerCase().includes(search.toLowerCase()) ||
        t.user.toLowerCase().includes(search.toLowerCase());
      const matchesStatus = statusFilter === "all" || t.status === statusFilter;
      const matchesType = typeFilter === "all" || t.type === typeFilter;
      return matchesSearch && matchesStatus && matchesType;
    });
  }, [recentTx, search, statusFilter, typeFilter]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / pageSize));
  const pageItems = filtered.slice((page - 1) * pageSize, page * pageSize);

  useEffect(() => setPage(1), [search, statusFilter, typeFilter]);

  const quickActions = [
    { label: "Fund Wallet", icon: PiggyBank, action: "fund" },
    { label: "Add User", icon: UserPlus, action: "adduser" },
    { label: "Send Broadcast", icon: Send, action: "broadcast" },
    { label: "Generate Report", icon: FileText, action: "report" },
  ];

  return (
    <div className="space-y-6">
      {/* Stat cards */}
      <div>
        <h2 className="text-sm font-semibold text-slate-500 mb-3 uppercase tracking-wide">Overview</h2>
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3 sm:gap-4">
          <StatCard label="Total Users" value={stats.totalUsers.toLocaleString()} icon={Users} accent={BRAND.info} delay={0} />
          <StatCard label="Active Users" value={stats.activeUsers.toLocaleString()} icon={CheckCircle2} accent={BRAND.success} delay={40} />
          <StatCard label="New Users Today" value={`+${stats.newUsersToday}`} icon={UserPlus} accent={BRAND.amber} delay={80} />
          <StatCard label="Wallet Balance" value={fmtNaira(stats.walletBalance)} icon={Wallet} accent={BRAND.amber} delay={120} />
          <StatCard label="Total Transactions" value={stats.totalTransactions.toLocaleString()} icon={ArrowLeftRight} accent={BRAND.info} delay={160} />
          <StatCard label="Pending Transactions" value={stats.pendingTransactions.toLocaleString()} icon={Clock} accent={BRAND.warning} delay={200} />
          <StatCard label="Successful Transactions" value={stats.successfulTransactions.toLocaleString()} icon={CheckCircle2} accent={BRAND.success} delay={240} />
          <StatCard label="Failed Transactions" value={stats.failedTransactions.toLocaleString()} icon={XCircle} accent={BRAND.danger} delay={280} />
          <StatCard label="Today's Revenue" value={fmtNaira(stats.todayRevenue)} icon={TrendingUp} accent={BRAND.success} delay={320} />
          <StatCard label="Monthly Revenue" value={fmtNaira(stats.monthlyRevenue)} icon={TrendingUp} accent={BRAND.success} delay={360} />
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <div className="lg:col-span-2 rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-semibold text-slate-900" style={{ fontFamily: "Sora, sans-serif" }}>Revenue (last 14 days)</h3>
            <span className="text-xs text-slate-400">Revenue vs. Payouts</span>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={revenueSeries} margin={{ left: -18, right: 8 }}>
                <defs>
                  <linearGradient id="rev" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor={BRAND.amber} stopOpacity={0.35} />
                    <stop offset="100%" stopColor={BRAND.amber} stopOpacity={0} />
                  </linearGradient>
                  <linearGradient id="pay" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor={BRAND.info} stopOpacity={0.25} />
                    <stop offset="100%" stopColor={BRAND.info} stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#EEF2F7" vertical={false} />
                <XAxis dataKey="label" tick={{ fontSize: 11, fill: "#94A3B8" }} axisLine={false} tickLine={false} />
                <YAxis tick={{ fontSize: 11, fill: "#94A3B8" }} axisLine={false} tickLine={false}
                  tickFormatter={(v) => `₦${(v / 1000).toFixed(0)}k`} />
                <Tooltip formatter={(v) => fmtNaira(v)} contentStyle={{ borderRadius: 12, border: "1px solid #EEF2F7", fontSize: 12 }} />
                <Area type="monotone" dataKey="revenue" stroke={BRAND.amber} strokeWidth={2} fill="url(#rev)" name="Revenue" />
                <Area type="monotone" dataKey="payouts" stroke={BRAND.info} strokeWidth={2} fill="url(#pay)" name="Payouts" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
          <h3 className="font-semibold text-slate-900 mb-1" style={{ fontFamily: "Sora, sans-serif" }}>Network Sales</h3>
          <p className="text-xs text-slate-400 mb-2">Share of sales by network this month</p>
          <div className="h-52">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={networkSales} dataKey="value" nameKey="name" innerRadius={50} outerRadius={78} paddingAngle={3}>
                  {networkSales.map((n) => <Cell key={n.name} fill={n.color} />)}
                </Pie>
                <Tooltip formatter={(v) => fmtNaira(v)} contentStyle={{ borderRadius: 12, border: "1px solid #EEF2F7", fontSize: 12 }} />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="grid grid-cols-2 gap-x-3 gap-y-2 mt-2">
            {networkSales.map((n) => (
              <div key={n.name} className="flex items-center gap-2 text-xs text-slate-600">
                <span className="h-2 w-2 rounded-full shrink-0" style={{ background: n.color }} />
                <span className="truncate">{n.name}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Quick actions */}
      <div className="rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
        <h3 className="font-semibold text-slate-900 mb-3" style={{ fontFamily: "Sora, sans-serif" }}>Quick Actions</h3>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {quickActions.map((q) => (
            <button
              key={q.action}
              onClick={() => onQuickAction(q.action)}
              className="group flex flex-col items-center justify-center gap-2 rounded-xl border border-slate-200 hover:border-blue-300 hover:bg-blue-50/60 transition-colors py-4"
            >
              <span className="rounded-lg p-2 bg-slate-100 group-hover:bg-white text-slate-600 group-hover:text-blue-600 transition-colors">
                <q.icon size={18} />
              </span>
              <span className="text-xs font-medium text-slate-700">{q.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Recent transactions */}
      <div className="rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 mb-4">
          <h3 className="font-semibold text-slate-900" style={{ fontFamily: "Sora, sans-serif" }}>Recent Transactions</h3>
          <div className="flex flex-col xs:flex-row gap-2 w-full sm:w-auto">
            <div className="relative">
              <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
              <input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Search ID or user…"
                className="w-full sm:w-56 rounded-lg border border-slate-200 pl-8 pr-3 py-1.5 text-sm outline-none focus:ring-2 focus:ring-blue-400/40 focus:border-blue-400"
              />
            </div>
            <select
              value={typeFilter}
              onChange={(e) => setTypeFilter(e.target.value)}
              className="rounded-lg border border-slate-200 px-2.5 py-1.5 text-sm text-slate-600 outline-none focus:ring-2 focus:ring-blue-400/40"
            >
              <option value="all">All Types</option>
              {TX_TYPES.map((t) => <option key={t.type} value={t.type}>{t.type}</option>)}
            </select>
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="rounded-lg border border-slate-200 px-2.5 py-1.5 text-sm text-slate-600 outline-none focus:ring-2 focus:ring-blue-400/40"
            >
              <option value="all">All Status</option>
              <option value="success">Successful</option>
              <option value="pending">Pending</option>
              <option value="failed">Failed</option>
            </select>
          </div>
        </div>

        <div className="overflow-x-auto -mx-4 sm:mx-0">
          <table className="w-full text-sm min-w-[640px]">
            <thead>
              <tr className="text-left text-xs uppercase tracking-wide text-slate-400 border-b border-slate-100">
                <th className="py-2.5 px-4 sm:px-2 font-medium">Transaction</th>
                <th className="py-2.5 px-2 font-medium">User</th>
                <th className="py-2.5 px-2 font-medium">Network</th>
                <th className="py-2.5 px-2 font-medium">Amount</th>
                <th className="py-2.5 px-2 font-medium">Status</th>
                <th className="py-2.5 px-2 font-medium">Date</th>
              </tr>
            </thead>
            <tbody>
              {pageItems.map((t) => (
                <tr key={t.id} className="border-b border-slate-50 hover:bg-slate-50/70 transition-colors">
                  <td className="py-2.5 px-4 sm:px-2">
                    <div className="flex items-center gap-2.5">
                      <span className="rounded-lg bg-slate-100 p-1.5 text-slate-500"><t.icon size={14} /></span>
                      <div>
                        <p className="font-medium text-slate-800">{t.type}</p>
                        <p className="text-xs text-slate-400">{t.id}</p>
                      </div>
                    </div>
                  </td>
                  <td className="py-2.5 px-2 text-slate-600">{t.user}</td>
                  <td className="py-2.5 px-2">
                    <span className="inline-flex items-center gap-1.5 text-slate-600">
                      <span className="h-2 w-2 rounded-full" style={{ background: t.networkColor }} />
                      {t.network}
                    </span>
                  </td>
                  <td className="py-2.5 px-2 font-medium text-slate-800">{fmtNaira(t.amount)}</td>
                  <td className="py-2.5 px-2"><StatusPill status={t.status} /></td>
                  <td className="py-2.5 px-2 text-slate-400 text-xs">
                    {t.date.toLocaleDateString("en-NG", { day: "2-digit", month: "short" })}, {t.date.toLocaleTimeString("en-NG", { hour: "2-digit", minute: "2-digit" })}
                  </td>
                </tr>
              ))}
              {pageItems.length === 0 && (
                <tr><td colSpan={6} className="py-8 text-center text-slate-400 text-sm">No transactions match your filters.</td></tr>
              )}
            </tbody>
          </table>
        </div>

        <div className="flex items-center justify-between mt-4 pt-3 border-t border-slate-100">
          <p className="text-xs text-slate-400">
            Showing {pageItems.length === 0 ? 0 : (page - 1) * pageSize + 1}–{Math.min(page * pageSize, filtered.length)} of {filtered.length}
          </p>
          <div className="flex items-center gap-1">
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
              className="rounded-lg p-1.5 border border-slate-200 text-slate-500 disabled:opacity-40 hover:bg-slate-50"
            >
              <ChevronLeft size={14} />
            </button>
            <span className="text-xs text-slate-500 px-2">{page} / {totalPages}</span>
            <button
              onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
              className="rounded-lg p-1.5 border border-slate-200 text-slate-500 disabled:opacity-40 hover:bg-slate-50"
            >
              <ChevronRight size={14} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Users Management page                                              */
