function exportReferralsCSV(rows, notify) {
  const headers = ["Referral ID", "Referrer", "Referrer Code", "Referee", "Referee Email", "Status", "Bonus Earned", "Txn Volume", "Date Joined"];
  const csvRows = rows.map((r) => [
    r.id, r.referrerName, r.referrerCode, r.refereeName, r.refereeEmail, r.status,
    r.bonusAmount, r.transactionVolume, r.joinDate.toLocaleString("en-NG"),
  ]);
  const csv = [headers, ...csvRows].map((row) => row.map((v) => `"${String(v).replace(/"/g, '""')}"`).join(",")).join("\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = "pancity-referrals.csv"; a.click();
  URL.revokeObjectURL(url);
  notify?.("Referrals exported to CSV");
}

function exportReferralsPDF(rows, notify) {
  const win = window.open("", "_blank");
  if (!win) { notify?.("Please allow pop-ups to export PDF"); return; }
  const rowsHtml = rows.map((r) => `
    <tr>
      <td>${r.id}</td><td>${r.referrerName}</td><td>${r.refereeName}</td>
      <td>${fmtNaira(r.bonusAmount)}</td><td>${r.status}</td>
      <td>${r.joinDate.toLocaleString("en-NG")}</td>
    </tr>`).join("");
  win.document.write(`
    <html><head><title>Pancity Referrals</title>
    <style>
      body{font-family:Arial,sans-serif;padding:24px;color:#0f172a;}
      h1{font-size:16px;margin-bottom:4px;} p{font-size:11px;color:#64748b;margin-top:0;}
      table{width:100%;border-collapse:collapse;font-size:11px;margin-top:16px;}
      th,td{border-bottom:1px solid #e2e8f0;text-align:left;padding:6px 8px;}
      th{background:#f8fafc;text-transform:uppercase;font-size:9px;letter-spacing:.04em;color:#64748b;}
    </style></head>
    <body>
      <h1>Pancity VTU — Referrals Report</h1>
      <p>Generated ${new Date().toLocaleString("en-NG")} · ${rows.length} records</p>
      <table><thead><tr><th>Referral ID</th><th>Referrer</th><th>Referee</th><th>Bonus</th><th>Status</th><th>Date</th></tr></thead>
      <tbody>${rowsHtml}</tbody></table>
      <script>window.onload = () => window.print();</script>
    </body></html>`);
  win.document.close();
  notify?.("Opening print dialog — choose \"Save as PDF\"");
}

function exportEarningsCSV(rows, notify) {
  const headers = ["Earning ID", "Referrer", "Referee", "Type", "Amount", "Status", "Date"];
  const csvRows = rows.map((e) => [e.id, e.referrerName, e.refereeName, e.type, e.amount, e.status, e.date.toLocaleString("en-NG")]);
  const csv = [headers, ...csvRows].map((row) => row.map((v) => `"${String(v).replace(/"/g, '""')}"`).join(",")).join("\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = "pancity-referral-earnings.csv"; a.click();
  URL.revokeObjectURL(url);
  notify?.("Earnings exported to CSV");
}

