function AdminRolesSection({ notify }) {
  const [list, setList] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [addOpen, setAddOpen] = useState(false);
  const [editTarget, setEditTarget] = useState(null);
  const [statusTarget, setStatusTarget] = useState(null);
  const [deleteTarget, setDeleteTarget] = useState(null);

  // Maps a backend admin document into the shape this page already
  // renders with — replacing the `admins` mock array entirely.
  function mapAdmin(a) {
    return {
      id: a._id,
      name: a.name || a.username,
      email: a.email || "",
      role: a.role,
      status: a.status,
      twoFAEnabled: a.twoFAEnabled,
      twoFAMethod: a.twoFAMethod,
      lastActive: a.lastActive ? new Date(a.lastActive) : new Date(a.createdAt),
    };
  }

  async function loadAdmins() {
    setLoading(true);
    try {
      const res = await api.listAdmins();
      setList(res.map(mapAdmin));
    } catch (err) {
      notify(err.message || "Failed to load admins");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => { loadAdmins(); }, []);

  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return list.filter((a) => {
      const matchesSearch = !q || a.name.toLowerCase().includes(q) || a.email.toLowerCase().includes(q);
      const matchesRole = roleFilter === "all" || a.role === roleFilter;
      return matchesSearch && matchesRole;
    });
  }, [list, search, roleFilter]);

  async function handleAdd(e, role) {
    const form = new FormData(e.target);
    try {
      const created = await api.createAdmin({
        name: form.get("name"),
        email: form.get("email"),
        username: form.get("username"),
        password: form.get("password"),
        role,
      });
      setList((prev) => [mapAdmin(created), ...prev]);
      notify(`${created.name} added as ${role}`);
      setAddOpen(false);
    } catch (err) {
      notify(err.message || "Failed to add admin");
    }
  }

  async function handleEdit(e, role) {
    const form = new FormData(e.target);
    const name = form.get("name");
    try {
      if (role !== editTarget.role) await api.updateAdminRole(editTarget.id, role);
      setList((prev) => prev.map((a) => a.id === editTarget.id ? { ...a, name, email: form.get("email"), role } : a));
      notify(`${name} updated`);
      setEditTarget(null);
    } catch (err) {
      notify(err.message || "Failed to update admin");
    }
  }

  async function toggleStatus() {
    const nowSuspended = statusTarget.status === "active";
    try {
      await api.setAdminStatus(statusTarget.id, nowSuspended ? "suspended" : "active");
      setList((prev) => prev.map((a) => a.id === statusTarget.id ? { ...a, status: nowSuspended ? "suspended" : "active" } : a));
      notify(`${statusTarget.name} ${nowSuspended ? "suspended" : "reactivated"}`);
    } catch (err) {
      notify(err.message || "Action failed");
    }
    setStatusTarget(null);
  }

  async function handleDelete() {
    try {
      await api.removeAdmin(deleteTarget.id);
      setList((prev) => prev.filter((a) => a.id !== deleteTarget.id));
      notify(`${deleteTarget.name} removed from admins`);
    } catch (err) {
      notify(err.message || "Failed to remove admin");
    }
    setDeleteTarget(null);
  }

  return (
    <div className="rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 mb-4">
        <div>
          <h3 className="font-semibold text-slate-900" style={{ fontFamily: "Sora, sans-serif" }}>Admin Roles</h3>
          <p className="text-xs text-slate-400 mt-0.5">{filtered.length} of {list.length} admins</p>
        </div>
        <div className="flex flex-col xs:flex-row flex-wrap gap-2">
          <div className="relative">
            <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search admins…"
              className="w-full sm:w-52 rounded-lg border border-slate-200 pl-8 pr-3 py-1.5 text-sm outline-none focus:ring-2 focus:ring-blue-400/40 focus:border-blue-400"
            />
          </div>
          <select value={roleFilter} onChange={(e) => setRoleFilter(e.target.value)}
            className="rounded-lg border border-slate-200 px-2.5 py-1.5 text-sm text-slate-600 outline-none focus:ring-2 focus:ring-blue-400/40">
            <option value="all">All Roles</option>
            {ADMIN_ROLES.map((r) => <option key={r} value={r}>{r}</option>)}
          </select>
          <button
            onClick={() => setAddOpen(true)}
            className="flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-sm font-medium text-slate-900"
            style={{ background: BRAND.amber }}
          >
            <Plus size={14} /> Add Admin
          </button>
        </div>
      </div>

      <div className="overflow-x-auto -mx-4 sm:mx-0">
        <table className="w-full text-sm min-w-[760px]">
          <thead>
            <tr className="text-left text-xs uppercase tracking-wide text-slate-400 border-b border-slate-100">
              <th className="py-2.5 px-4 sm:px-2 font-medium">Admin</th>
              <th className="py-2.5 px-2 font-medium">Role</th>
              <th className="py-2.5 px-2 font-medium">Status</th>
              <th className="py-2.5 px-2 font-medium">Last Active</th>
              <th className="py-2.5 px-2 font-medium text-right">Actions</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map((a) => (
              <tr key={a.id} className="border-b border-slate-50 hover:bg-slate-50/70 transition-colors">
                <td className="py-2.5 px-4 sm:px-2">
                  <div className="flex items-center gap-2.5">
                    <div className="h-8 w-8 rounded-full bg-slate-800 text-white flex items-center justify-center text-[11px] font-medium shrink-0">
                      {initials(a.name)}
                    </div>
                    <div className="min-w-0">
                      <p className="font-medium text-slate-800 truncate">{a.name}</p>
                      <p className="text-xs text-slate-400 truncate">{a.email}</p>
                    </div>
                  </div>
                </td>
                <td className="py-2.5 px-2"><RoleBadge role={a.role} /></td>
                <td className="py-2.5 px-2"><UserStatusPill status={a.status} /></td>
                <td className="py-2.5 px-2 text-slate-400 text-xs">{timeAgo(a.lastActive)}</td>
                <td className="py-2.5 px-2">
                  <div className="flex items-center justify-end gap-0.5">
                    <IconBtn title="Edit admin" onClick={() => setEditTarget(a)}><Pencil size={15} /></IconBtn>
                    {a.status === "active" ? (
                      <IconBtn title="Suspend admin" tone="rose" onClick={() => setStatusTarget(a)} disabled={a.role === "Super Admin"}><Ban size={15} /></IconBtn>
                    ) : (
                      <IconBtn title="Reactivate admin" tone="emerald" onClick={() => setStatusTarget(a)}><UserCheck size={15} /></IconBtn>
                    )}
                    <IconBtn title="Remove admin" tone="rose" onClick={() => setDeleteTarget(a)} disabled={a.role === "Super Admin"}><Trash2 size={15} /></IconBtn>
                  </div>
                </td>
              </tr>
            ))}
            {filtered.length === 0 && (
              <tr><td colSpan={5} className="py-8 text-center text-slate-400 text-sm">No admins match your filters.</td></tr>
            )}
          </tbody>
        </table>
      </div>

      <Modal open={addOpen} onClose={() => setAddOpen(false)} title="Add Admin">
        <AdminForm onSubmit={handleAdd} submitLabel="Add Admin" />
      </Modal>
      <Modal open={!!editTarget} onClose={() => setEditTarget(null)} title="Edit Admin">
        {editTarget && <AdminForm initial={editTarget} onSubmit={handleEdit} submitLabel="Save Changes" />}
      </Modal>
      <ConfirmDialog
        open={!!statusTarget} onClose={() => setStatusTarget(null)} onConfirm={toggleStatus}
        title={statusTarget?.status === "active" ? "Suspend Admin" : "Reactivate Admin"}
        confirmLabel={statusTarget?.status === "active" ? "Suspend" : "Reactivate"}
        danger={statusTarget?.status === "active"}
        message={statusTarget ? `${statusTarget.name} will ${statusTarget.status === "active" ? "immediately lose access to the admin panel" : "regain access to the admin panel"}.` : ""}
      />
      <ConfirmDialog
        open={!!deleteTarget} onClose={() => setDeleteTarget(null)} onConfirm={handleDelete}
        title="Remove Admin" confirmLabel="Remove Permanently" danger
        message={deleteTarget ? `This will permanently remove ${deleteTarget.name} from the admin panel. This action cannot be undone.` : ""}
      />
    </div>
  );
}

/* ---- Permissions ---------------------------------------------------- */
function PermissionsSection({ notify }) {
  const [matrix, setMatrix] = useState(DEFAULT_ROLE_PERMISSIONS);
  const [dirtyRoles, setDirtyRoles] = useState(new Set());
  const [loading, setLoading] = useState(true);

  async function load() {
    setLoading(true);
    try {
      const templates = await api.listRoleTemplates();
      const next = { ...DEFAULT_ROLE_PERMISSIONS };
      templates.forEach((t) => { next[t.role] = t.permissions; });
      setMatrix(next);
    } catch (err) {
      notify(err.message || "Failed to load permissions");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => { load(); }, []);

  function toggle(role, key) {
    if (role === "Super Admin") return;
    setMatrix((prev) => ({ ...prev, [role]: { ...prev[role], [key]: !prev[role][key] } }));
    setDirtyRoles((prev) => new Set(prev).add(role));
  }

  async function handleSave() {
    try {
      await Promise.all(
        [...dirtyRoles].map((role) => api.updateRoleTemplate(role, matrix[role]))
      );
      notify("Permissions updated");
      setDirtyRoles(new Set());
    } catch (err) {
      notify(err.message || "Failed to save permissions");
    }
  }

  return (
    <div className="rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 mb-4">
        <div>
          <h3 className="font-semibold text-slate-900" style={{ fontFamily: "Sora, sans-serif" }}>Role Permissions</h3>
          <p className="text-xs text-slate-400 mt-0.5">Control what each role can see and do across the admin panel</p>
        </div>
        <button
          onClick={handleSave}
          disabled={dirtyRoles.size === 0}
          className="flex items-center gap-1.5 rounded-lg px-4 py-2 text-sm font-medium text-slate-900 disabled:opacity-50 shrink-0"
          style={{ background: BRAND.amber }}
        >
          <CheckCircle2 size={14} /> Save Permissions
        </button>
      </div>

      <div className="overflow-x-auto -mx-4 sm:mx-0">
        <table className="w-full text-sm min-w-[720px]">
          <thead>
            <tr className="text-left text-xs uppercase tracking-wide text-slate-400 border-b border-slate-100">
              <th className="py-2.5 px-4 sm:px-2 font-medium">Permission</th>
              {ADMIN_ROLES.map((r) => (
                <th key={r} className="py-2.5 px-2 font-medium text-center">{r}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {PERMISSION_GROUPS.map((g) => (
              <React.Fragment key={g.group}>
                <tr>
                  <td colSpan={ADMIN_ROLES.length + 1} className="pt-4 pb-1 px-4 sm:px-2 text-[11px] font-semibold uppercase tracking-wide text-slate-400">
                    {g.group}
                  </td>
                </tr>
                {g.permissions.map((p) => (
                  <tr key={p.key} className="border-b border-slate-50 hover:bg-slate-50/70">
                    <td className="py-2.5 px-4 sm:px-2 text-slate-700">{p.label}</td>
                    {ADMIN_ROLES.map((role) => (
                      <td key={role} className="py-2.5 px-2 text-center">
                        <input
                          type="checkbox"
                          checked={!!matrix[role][p.key]}
                          disabled={role === "Super Admin"}
                          onChange={() => toggle(role, p.key)}
                          className="h-4 w-4 rounded border-slate-300 accent-blue-500 disabled:opacity-40"
                        />
                      </td>
                    ))}
                  </tr>
                ))}
              </React.Fragment>
            ))}
          </tbody>
        </table>
      </div>
      <p className="text-xs text-slate-400 mt-3">Super Admin always has full access and cannot be restricted.</p>
    </div>
  );
}

/* ---- Two-Factor Authentication --------------------------------------- */
function TwoFactorSection({ notify }) {
  const [require2FA, setRequire2FA] = useState(true);
  const [list, setList] = useState([]);
  const [resetTarget, setResetTarget] = useState(null);

  useEffect(() => {
    api.listAdmins()
      .then((res) => setList(res.map((a) => ({
        id: a._id,
        name: a.name || a.username,
        role: a.role,
        twoFAEnabled: a.twoFAEnabled,
        twoFAMethod: a.twoFAMethod,
      }))))
      .catch((err) => notify(err.message || "Failed to load admins"));
  }, []);

  async function handleReset() {
    try {
      await api.resetAdminTwoFA(resetTarget.id);
      setList((prev) => prev.map((a) => a.id === resetTarget.id ? { ...a, twoFAEnabled: false, twoFAMethod: null } : a));
      notify(`2FA reset for ${resetTarget.name} — they'll be prompted to re-enroll at next login`);
    } catch (err) {
      notify(err.message || "Failed to reset 2FA");
    }
    setResetTarget(null);
  }

  const enrolledCount = list.filter((a) => a.twoFAEnabled).length;

  return (
    <div className="space-y-6">
      <div className="rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
        <div className="flex items-center justify-between gap-4 flex-wrap">
          <div className="flex items-center gap-3">
            <span className="rounded-xl p-2.5" style={{ background: require2FA ? `${BRAND.success}1A` : "#F1F5F9", color: require2FA ? BRAND.success : "#94A3B8" }}>
              <Fingerprint size={18} />
            </span>
            <div>
              <h3 className="font-semibold text-slate-900" style={{ fontFamily: "Sora, sans-serif" }}>Require Two-Factor Authentication</h3>
              <p className="text-xs text-slate-400 mt-0.5">
                {require2FA ? "All admins must verify with a second factor at login" : "2FA is currently optional for admins"} · {enrolledCount}/{list.length} enrolled
              </p>
            </div>
          </div>
          <ToggleSwitch
            checked={require2FA}
            onChange={(v) => { setRequire2FA(v); notify(v ? "2FA is now required for all admins" : "2FA requirement disabled"); }}
            label=""
          />
        </div>
      </div>

      <div className="rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
        <h3 className="font-semibold text-slate-900 mb-4" style={{ fontFamily: "Sora, sans-serif" }}>Admin 2FA Status</h3>
        <div className="overflow-x-auto -mx-4 sm:mx-0">
          <table className="w-full text-sm min-w-[620px]">
            <thead>
              <tr className="text-left text-xs uppercase tracking-wide text-slate-400 border-b border-slate-100">
                <th className="py-2.5 px-4 sm:px-2 font-medium">Admin</th>
                <th className="py-2.5 px-2 font-medium">Role</th>
                <th className="py-2.5 px-2 font-medium">2FA Status</th>
                <th className="py-2.5 px-2 font-medium">Method</th>
                <th className="py-2.5 px-2 font-medium text-right">Actions</th>
              </tr>
            </thead>
            <tbody>
              {list.map((a) => (
                <tr key={a.id} className="border-b border-slate-50 hover:bg-slate-50/70 transition-colors">
                  <td className="py-2.5 px-4 sm:px-2">
                    <div className="flex items-center gap-2.5">
                      <div className="h-8 w-8 rounded-full bg-slate-800 text-white flex items-center justify-center text-[11px] font-medium shrink-0">
                        {initials(a.name)}
                      </div>
                      <p className="font-medium text-slate-800 truncate">{a.name}</p>
                    </div>
                  </td>
                  <td className="py-2.5 px-2"><RoleBadge role={a.role} /></td>
                  <td className="py-2.5 px-2"><TwoFAPill enabled={a.twoFAEnabled} /></td>
                  <td className="py-2.5 px-2 text-slate-500 text-xs">{a.twoFAEnabled ? a.twoFAMethod : "—"}</td>
                  <td className="py-2.5 px-2">
                    <div className="flex items-center justify-end">
                      {a.twoFAEnabled && (
                        <IconBtn title="Reset 2FA" tone="rose" onClick={() => setResetTarget(a)}><KeyRound size={15} /></IconBtn>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <ConfirmDialog
        open={!!resetTarget} onClose={() => setResetTarget(null)} onConfirm={handleReset}
        title="Reset 2FA" confirmLabel="Reset 2FA" danger
        message={resetTarget ? `${resetTarget.name} will be signed out of their current 2FA method and required to set it up again on next login.` : ""}
      />
    </div>
  );
}

/* ---- Login Logs -------------------------------------------------------- */
function LoginLogsSection() {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [page, setPage] = useState(1);
  const [toast, setToast] = useState(null);
  const pageSize = 8;

  function notify(msg) {
    setToast(msg);
    setTimeout(() => setToast(null), 2200);
  }

  useEffect(() => {
    setLoading(true);
    api.listLoginLogs({ limit: 200 })
      .then((res) => setLogs((res.items || []).map((l) => ({
        id: l._id,
        adminName: l.adminName,
        ip: l.ip || "—",
        device: l.device || "—",
        location: l.location || "—",
        status: l.status,
        reason: l.reason,
        date: new Date(l.createdAt),
      }))))
      .catch((err) => notify(err.message || "Failed to load login logs"))
      .finally(() => setLoading(false));
  }, []);

  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return logs.filter((l) => {
      const matchesSearch = !q || l.adminName.toLowerCase().includes(q) || l.ip.includes(q) || l.location.toLowerCase().includes(q);
      const matchesStatus = statusFilter === "all" || l.status === statusFilter;
      return matchesSearch && matchesStatus;
    });
  }, [logs, search, statusFilter]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / pageSize));
  const pageItems = filtered.slice((page - 1) * pageSize, page * pageSize);

  function handleExport() {
    exportLogsCSV(
      filtered,
      ["Admin", "IP Address", "Device", "Location", "Status", "Reason", "Date"],
      (l) => [l.adminName, l.ip, l.device, l.location, l.status, l.reason || "-", l.date.toLocaleString("en-NG")],
      "pancity-login-logs.csv",
      notify
    );
  }

  return (
    <div className="rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 mb-4">
        <div>
          <h3 className="font-semibold text-slate-900" style={{ fontFamily: "Sora, sans-serif" }}>Login Logs</h3>
          <p className="text-xs text-slate-400 mt-0.5">{filtered.length} of {logs.length} attempts</p>
        </div>
        <div className="flex flex-col xs:flex-row flex-wrap gap-2">
          <div className="relative">
            <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
            <input
              value={search}
              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
              placeholder="Search admin, IP, location…"
              className="w-full sm:w-56 rounded-lg border border-slate-200 pl-8 pr-3 py-1.5 text-sm outline-none focus:ring-2 focus:ring-blue-400/40 focus:border-blue-400"
            />
          </div>
          <select value={statusFilter} onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
            className="rounded-lg border border-slate-200 px-2.5 py-1.5 text-sm text-slate-600 outline-none focus:ring-2 focus:ring-blue-400/40">
            <option value="all">All Status</option>
            <option value="success">Successful</option>
            <option value="failed">Failed</option>
          </select>
          <button
            onClick={handleExport}
            className="flex items-center gap-1.5 rounded-lg border border-slate-200 px-3 py-1.5 text-sm text-slate-600 hover:bg-slate-50"
          >
            <Download size={14} /> Export
          </button>
        </div>
      </div>

      <div className="overflow-x-auto -mx-4 sm:mx-0">
        <table className="w-full text-sm min-w-[760px]">
          <thead>
            <tr className="text-left text-xs uppercase tracking-wide text-slate-400 border-b border-slate-100">
              <th className="py-2.5 px-4 sm:px-2 font-medium">Admin</th>
              <th className="py-2.5 px-2 font-medium">IP Address</th>
              <th className="py-2.5 px-2 font-medium">Device</th>
              <th className="py-2.5 px-2 font-medium">Location</th>
              <th className="py-2.5 px-2 font-medium">Status</th>
              <th className="py-2.5 px-2 font-medium">Time</th>
            </tr>
          </thead>
          <tbody>
            {pageItems.map((l) => (
              <tr key={l.id} className="border-b border-slate-50 hover:bg-slate-50/70 transition-colors">
                <td className="py-2.5 px-4 sm:px-2 font-medium text-slate-800">{l.adminName}</td>
                <td className="py-2.5 px-2 text-slate-500 font-mono text-xs">{l.ip}</td>
                <td className="py-2.5 px-2 text-slate-500">{l.device}</td>
                <td className="py-2.5 px-2 text-slate-500">{l.location}</td>
                <td className="py-2.5 px-2">
                  <StatusPill status={l.status} />
                  {l.reason && <p className="text-[11px] text-rose-400 mt-0.5">{l.reason}</p>}
                </td>
                <td className="py-2.5 px-2 text-slate-400 text-xs">{timeAgo(l.date)}</td>
              </tr>
            ))}
            {pageItems.length === 0 && (
              <tr><td colSpan={6} className="py-8 text-center text-slate-400 text-sm">No login attempts match your filters.</td></tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="flex items-center justify-between mt-4 pt-3 border-t border-slate-100">
        <p className="text-xs text-slate-400">
          Showing {pageItems.length === 0 ? 0 : (page - 1) * pageSize + 1}–{Math.min(page * pageSize, filtered.length)} of {filtered.length}
        </p>
        <div className="flex items-center gap-1">
          <button
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            disabled={page === 1}
            className="rounded-lg p-1.5 border border-slate-200 text-slate-500 disabled:opacity-40 hover:bg-slate-50"
          >
            <ChevronLeft size={14} />
          </button>
          <span className="text-xs text-slate-500 px-2">{page} / {totalPages}</span>
          <button
            onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
            disabled={page === totalPages}
            className="rounded-lg p-1.5 border border-slate-200 text-slate-500 disabled:opacity-40 hover:bg-slate-50"
          >
            <ChevronRight size={14} />
          </button>
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 -translate-x-1/2 z-[60] rounded-xl bg-slate-900 text-white text-sm px-4 py-2.5 shadow-lg flex items-center gap-2 animate-[fadeIn_.15s_ease-out]">
          <CheckCircle2 size={15} className="text-emerald-400" />
          {toast}
        </div>
      )}
    </div>
  );
}

