/* ------------------------------------------------------------------ */
/*  Maintenance Page — shown to non-admin users while maintenance      */
/*  mode is active. Admins bypass this and keep dashboard access.      */
/* ------------------------------------------------------------------ */
function MaintenanceCountdown({ endTime }) {
  const [now, setNow] = useState(() => Date.now());
  useEffect(() => {
    const t = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(t);
  }, []);
  if (!endTime) return null;
  const target = new Date(endTime).getTime();
  if (Number.isNaN(target)) return null;
  const diff = target - now;
  if (diff <= 0) {
    return (
      <p className="text-xs font-medium text-emerald-600">Maintenance window has ended — refreshing shortly.</p>
    );
  }
  const h = Math.floor(diff / 3.6e6);
  const m = Math.floor((diff % 3.6e6) / 60000);
  const s = Math.floor((diff % 60000) / 1000);
  const pad = (n) => String(n).padStart(2, "0");
  return (
    <div className="flex items-center gap-2">
      {[["Hrs", h], ["Min", m], ["Sec", s]].map(([label, val]) => (
        <div key={label} className="flex flex-col items-center rounded-xl bg-white/10 px-3 py-2 min-w-[56px]">
          <span className="text-xl font-bold text-white tabular-nums" style={{ fontFamily: "Sora, sans-serif" }}>{pad(val)}</span>
          <span className="text-[10px] uppercase tracking-wide text-slate-400">{label}</span>
        </div>
      ))}
    </div>
  );
}

function MaintenancePage({ maintenance, isAdminPreview, onExitPreview }) {
  const formattedEnd = (() => {
    if (!maintenance.endTime) return null;
    const d = new Date(maintenance.endTime);
    if (Number.isNaN(d.getTime())) return null;
    return d.toLocaleString("en-NG", { dateStyle: "medium", timeStyle: "short" });
  })();

  return (
    <div
      className="min-h-screen flex items-center justify-center px-4 py-10 relative overflow-hidden"
      style={{ background: `radial-gradient(circle at 20% 20%, ${BRAND.inkSoft}, ${BRAND.ink} 70%)`, fontFamily: "Inter, sans-serif" }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=Sora:wght@600;700&display=swap');
        @keyframes floatSlow { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-10px); } }
      `}</style>

      {/* Decorative glow */}
      <div className="absolute -top-24 -right-24 h-72 w-72 rounded-full opacity-20 blur-3xl" style={{ background: BRAND.amber }} />
      <div className="absolute -bottom-24 -left-24 h-72 w-72 rounded-full opacity-10 blur-3xl" style={{ background: BRAND.info }} />

      {isAdminPreview && (
        <button
          onClick={onExitPreview}
          className="absolute top-4 right-4 sm:top-6 sm:right-6 z-10 flex items-center gap-1.5 rounded-lg bg-white/10 hover:bg-white/20 text-white text-xs font-medium px-3 py-2 backdrop-blur"
        >
          <X size={13} /> Exit Preview
        </button>
      )}

      <div className="relative w-full max-w-md text-center">
        <div
          className="mx-auto mb-6 h-16 w-16 rounded-2xl flex items-center justify-center"
          style={{ background: BRAND.amber, animation: "floatSlow 3.5s ease-in-out infinite" }}
        >
          <Power size={28} className="text-slate-900" />
        </div>

        <h1 className="text-2xl sm:text-3xl font-bold text-white mb-2" style={{ fontFamily: "Sora, sans-serif" }}>
          We'll be right back
        </h1>
        <p className="text-sm text-slate-400 leading-relaxed mb-6">
          {maintenance.message || "We're currently performing scheduled maintenance. Please check back shortly."}
        </p>

        {maintenance.endTime && (
          <div className="mb-6 flex flex-col items-center gap-2">
            <MaintenanceCountdown endTime={maintenance.endTime} />
            {formattedEnd && <p className="text-[11px] text-slate-500">Estimated back online: {formattedEnd}</p>}
          </div>
        )}

        <div className="rounded-2xl bg-white/5 border border-white/10 px-5 py-4 text-left">
          <p className="text-xs font-medium text-slate-300 mb-3">Need urgent help? Reach our support team:</p>
          <div className="space-y-2">
            {maintenance.supportEmail && (
              <a href={`mailto:${maintenance.supportEmail}`} className="flex items-center gap-2.5 text-sm text-white hover:text-blue-300">
                <span className="rounded-lg p-1.5 bg-white/10"><Mail size={13} /></span>
                {maintenance.supportEmail}
              </a>
            )}
            {maintenance.supportPhone && (
              <a href={`tel:${maintenance.supportPhone}`} className="flex items-center gap-2.5 text-sm text-white hover:text-blue-300">
                <span className="rounded-lg p-1.5 bg-white/10"><Phone size={13} /></span>
                {maintenance.supportPhone}
              </a>
            )}
          </div>
        </div>

        <p className="mt-6 text-[11px] text-slate-500">Pancity VTU — Admins can sign in as usual during this window.</p>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Admin login page                                                   */
/* ------------------------------------------------------------------ */
function LoginPage({ onLogin }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  // Plain function (not a form submit handler) — some preview/sandbox
  // environments block native <form> submission, so this is triggered
  // directly from the button's onClick and from Enter keypresses.
  async function attemptLogin() {
    setError("");
    if (!username.trim() || !password.trim()) {
      setError("Please enter both username and password.");
      return;
    }
    setLoading(true);
    try {
      const res = await api.adminLogin(username.trim(), password);
      setAdminToken(res.token);
      onLogin(res.admin?.username || username.trim());
    } catch (err) {
      setError(err.message || "Invalid username or password.");
    } finally {
      setLoading(false);
    }
  }

  function handleKeyDown(e) {
    if (e.key === "Enter") attemptLogin();
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#F4F6FB] px-4" style={{ fontFamily: "Inter, sans-serif" }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=Sora:wght@600;700&display=swap');`}</style>
      <div className="w-full max-w-sm">
        <div className="flex flex-col items-center mb-6">
          <img
            src={LOGO_DATA_URI}
            alt="Pancity logo"
            className="h-16 w-16 object-contain mb-3"
          />
          <h1 className="text-lg font-semibold text-slate-900" style={{ fontFamily: "Sora, sans-serif" }}>
            Pancity Admin
          </h1>
          <p className="text-xs text-slate-400 mt-1">Sign in to manage your platform</p>
        </div>

        <div className="rounded-2xl bg-white border border-slate-200 shadow-sm p-6">
          {error && (
            <div
              className="mb-4 rounded-lg px-3 py-2 text-xs flex items-center gap-2"
              style={{ background: `${BRAND.danger}12`, color: BRAND.danger }}
            >
              <AlertTriangle size={13} className="shrink-0" /> {error}
            </div>
          )}

          <label className="block mb-3">
            <span className="block text-xs font-medium text-slate-600 mb-1">Username</span>
            <input
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="admin"
              autoFocus
              className="w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 outline-none focus:ring-2 focus:ring-blue-400/40 focus:border-blue-400"
            />
          </label>

          <label className="block mb-4">
            <span className="block text-xs font-medium text-slate-600 mb-1">Password</span>
            <div className="relative">
              <input
                type={showPassword ? "text" : "password"}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="••••••••"
                className="w-full rounded-lg border border-slate-200 pl-3 pr-9 py-2 text-sm text-slate-800 outline-none focus:ring-2 focus:ring-blue-400/40 focus:border-blue-400"
              />
              <button
                type="button"
                onClick={() => setShowPassword((s) => !s)}
                className="absolute right-2.5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              >
                {showPassword ? <EyeOff size={15} /> : <Eye size={15} />}
              </button>
            </div>
          </label>

          <button
            type="button"
            onClick={attemptLogin}
            disabled={loading}
            className="w-full rounded-lg py-2.5 text-sm font-medium text-slate-900 flex items-center justify-center gap-2 disabled:opacity-60"
            style={{ background: BRAND.amber }}
          >
            {loading ? <RefreshCcw size={14} className="animate-spin" /> : <Lock size={14} />}
            {loading ? "Signing in…" : "Sign In"}
          </button>

          <p className="text-[11px] text-slate-400 mt-4 text-center">
            Demo credentials — username: <span className="font-medium text-slate-500">admin</span>, password:{" "}
            <span className="font-medium text-slate-500">admin123</span>
          </p>
        </div>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Splash screen shown briefly after a successful login               */
/* ------------------------------------------------------------------ */
function SplashPage({ username, onDone }) {
  useEffect(() => {
    const t = setTimeout(onDone, 1800);
    return () => clearTimeout(t);
  }, [onDone]);

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#0B1120] px-4" style={{ fontFamily: "Inter, sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=Sora:wght@600;700&display=swap');
        @keyframes splashPop { 0% { opacity:0; transform: scale(.85);} 100% { opacity:1; transform: scale(1);} }
        @keyframes splashFade { 0% { opacity:0; transform: translateY(6px);} 100% { opacity:1; transform: translateY(0);} }
      `}</style>
      <div className="flex flex-col items-center text-center">
        <img
          src={LOGO_DATA_URI}
          alt="Pancity logo"
          className="h-20 w-20 object-contain mb-5"
          style={{ animation: "splashPop .4s ease-out" }}
        />
        <h1
          className="text-xl font-semibold text-white mb-1"
          style={{ fontFamily: "Sora, sans-serif", animation: "splashFade .4s ease-out .1s both" }}
        >
          Pancity VTU
        </h1>
        <p
          className="text-sm text-slate-400 mb-6"
          style={{ animation: "splashFade .4s ease-out .2s both" }}
        >
          Welcome back{username ? `, ${username}` : ""}
        </p>
        <div className="flex items-center gap-1.5" style={{ animation: "splashFade .4s ease-out .3s both" }}>
          <span className="h-1.5 w-1.5 rounded-full animate-bounce" style={{ background: BRAND.amber, animationDelay: "0ms" }} />
          <span className="h-1.5 w-1.5 rounded-full animate-bounce" style={{ background: BRAND.amber, animationDelay: "120ms" }} />
          <span className="h-1.5 w-1.5 rounded-full animate-bounce" style={{ background: BRAND.amber, animationDelay: "240ms" }} />
        </div>
      </div>
    </div>
  );
}

export default function PancityAdminDashboard() {
  const [stage, setStage] = useState("login"); // "login" | "splash" | "app"
  const [auth, setAuth] = useState({ username: "" });
  const [active, setActive] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [modal, setModal] = useState(null);
  const [toast, setToast] = useState(null);
  const [previewAsUser, setPreviewAsUser] = useState(false);
  const [maintenance, setMaintenance] = useState({
    enabled: false,
    adminOnly: true,
    message: "We're currently performing scheduled maintenance. Please check back shortly.",
    endTime: "",
    supportEmail: "support@pancity.ng",
    supportPhone: "08012345678",
  });

  // Pull-to-refresh — lets touch/mobile users pull down at the top of the
  // page to reload the current view, same gesture as the customer app.
  const [pullDistance, setPullDistance] = useState(0);
  const [refreshing, setRefreshing] = useState(false);
  const pullStartY = useRef(null);
  const pullRafId = useRef(null);
  const PULL_THRESHOLD = 70;

  const activeItem = NAV_ITEMS.find((n) => n.key === active);

  function showToast(msg) {
    setToast(msg);
    setTimeout(() => setToast(null), 2400);
  }

  function handleQuickAction(action) {
    setModal(action);
  }

  function handleLogout() {
    setAuth({ username: "" });
    setStage("login");
    setActive("dashboard");
  }

  const handleTouchStart = (e) => {
    const scrollTop = document.scrollingElement ? document.scrollingElement.scrollTop : window.scrollY;
    if (scrollTop <= 0 && !refreshing) {
      pullStartY.current = e.touches[0].clientY;
    } else {
      pullStartY.current = null;
    }
  };

  const handleTouchMove = (e) => {
    if (pullStartY.current === null || refreshing) return;
    const delta = e.touches[0].clientY - pullStartY.current;
    if (delta > 0) {
      if (pullRafId.current !== null) cancelAnimationFrame(pullRafId.current);
      pullRafId.current = requestAnimationFrame(() => {
        setPullDistance(Math.min(delta * 0.5, PULL_THRESHOLD * 1.4));
      });
    } else if (pullStartY.current !== null) {
      pullStartY.current = null;
      setPullDistance(0);
    }
  };

  const handleTouchEnd = () => {
    if (pullRafId.current !== null) {
      cancelAnimationFrame(pullRafId.current);
      pullRafId.current = null;
    }
    if (pullDistance >= PULL_THRESHOLD && !refreshing) {
      setRefreshing(true);
      setPullDistance(PULL_THRESHOLD);
      setTimeout(() => {
        setRefreshing(false);
        setPullDistance(0);
        showToast("Data refreshed");
      }, 1000);
    } else {
      setPullDistance(0);
    }
    pullStartY.current = null;
  };

  if (stage === "login") {
    return (
      <LoginPage
        onLogin={(username) => {
          setAuth({ username });
          setStage("splash");
        }}
      />
    );
  }

  if (stage === "splash") {
    return <SplashPage username={auth.username} onDone={() => setStage("app")} />;
  }

  if (previewAsUser) {
    return (
      <MaintenancePage
        maintenance={maintenance}
        isAdminPreview
        onExitPreview={() => setPreviewAsUser(false)}
      />
    );
  }

  return (
    <div className="min-h-screen bg-[#F4F6FB] text-slate-800" style={{ fontFamily: "Inter, sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=Sora:wght@600;700&display=swap');
        @keyframes fadeIn { from { opacity: 0; transform: translateY(4px);} to { opacity:1; transform:translateY(0);} }
      `}</style>

      {/* Mobile overlay */}
      {sidebarOpen && (
        <div className="fixed inset-0 z-40 bg-slate-900/50 lg:hidden" onClick={() => setSidebarOpen(false)} />
      )}

      {/* Sidebar */}
      <aside
        className={`fixed z-50 lg:z-0 top-0 left-0 h-full w-64 shrink-0 flex flex-col transition-transform duration-200 lg:translate-x-0 ${
          sidebarOpen ? "translate-x-0" : "-translate-x-full"
        } lg:sticky lg:top-0`}
        style={{ background: BRAND.ink }}
      >
        <div className="flex items-center justify-between px-5 h-16 border-b border-white/5">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 rounded-lg flex items-center justify-center font-bold text-slate-900" style={{ background: BRAND.amber, fontFamily: "Sora, sans-serif" }}>P</div>
            <span className="text-white font-semibold tracking-tight" style={{ fontFamily: "Sora, sans-serif" }}>Pancity VTU</span>
          </div>
          <button className="lg:hidden text-white/60" onClick={() => setSidebarOpen(false)}>
            <X size={18} />
          </button>
        </div>

        <nav className="flex-1 overflow-y-auto py-4 px-3 space-y-1">
          {NAV_ITEMS.map((item) => {
            const isActive = active === item.key;
            return (
              <button
                key={item.key}
                onClick={() => { setActive(item.key); setSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 rounded-xl px-3 py-2.5 text-sm transition-colors ${
                  isActive ? "text-slate-900 font-medium" : "text-slate-300 hover:bg-white/5 hover:text-white"
                }`}
                style={isActive ? { background: BRAND.amber } : {}}
              >
                <item.icon size={17} />
                {item.label}
              </button>
            );
          })}

          <div className="my-2 border-t border-white/5" />

          <button
            onClick={handleLogout}
            className="w-full flex items-center gap-3 rounded-xl px-3 py-2.5 text-sm text-rose-400 hover:bg-rose-500/10 hover:text-rose-300 transition-colors"
          >
            <Power size={17} />
            Logout
          </button>
        </nav>

        <div className="p-4 border-t border-white/5">
          <div className="rounded-xl bg-white/5 p-3 flex items-center gap-3">
            <div className="h-9 w-9 rounded-full bg-blue-400/20 text-blue-300 flex items-center justify-center text-xs font-semibold">
              {(auth.username || "Admin").slice(0, 2).toUpperCase()}
            </div>
            <div className="min-w-0">
              <p className="text-xs font-medium text-white truncate">{auth.username || "Admin User"}</p>
              <p className="text-[11px] text-slate-400 truncate">admin@pancity.ng</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Main column */}
      <div className="lg:pl-64" onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd}>
        {/* Pull-to-refresh indicator */}
        <div
          className="flex items-center justify-center overflow-hidden transition-[height] duration-200 ease-out"
          style={{ height: pullDistance }}
        >
          <RefreshCcw
            size={18}
            className={`text-blue-500 ${refreshing ? "animate-spin" : ""}`}
            style={!refreshing ? { transform: `rotate(${(pullDistance / PULL_THRESHOLD) * 180}deg)`, transition: "transform 0.1s linear" } : undefined}
          />
        </div>

        {/* Topbar */}
        <header className="sticky top-0 z-30 flex items-center justify-between gap-3 h-16 px-4 sm:px-6 bg-white/80 backdrop-blur border-b border-slate-200/70">
          <div className="flex items-center gap-3">
            <button className="lg:hidden text-slate-500" onClick={() => setSidebarOpen(true)}>
              <Menu size={20} />
            </button>
            <div>
              <h1 className="text-base sm:text-lg font-semibold text-slate-900" style={{ fontFamily: "Sora, sans-serif" }}>
                {activeItem.label}
              </h1>
              <p className="text-xs text-slate-400 hidden sm:block">Welcome back, here's what's happening today.</p>
            </div>
          </div>
          <div className="flex items-center gap-2 sm:gap-3">
            <button
              onClick={() => {
                if (refreshing) return;
                setRefreshing(true);
                setTimeout(() => {
                  setRefreshing(false);
                  showToast("Data refreshed");
                }, 800);
              }}
              className="hidden sm:flex items-center gap-1.5 rounded-lg border border-slate-200 px-3 py-1.5 text-xs text-slate-600 hover:bg-slate-50"
            >
              <RefreshCcw size={13} className={refreshing ? "animate-spin" : ""} /> Refresh
            </button>
            <button className="relative rounded-lg p-2 text-slate-500 hover:bg-slate-100">
              <Bell size={18} />
              <span className="absolute top-1.5 right-1.5 h-1.5 w-1.5 rounded-full bg-rose-500" />
            </button>
            <div className="flex items-center gap-2 rounded-lg pl-2 pr-1 py-1 hover:bg-slate-100 cursor-pointer">
              <div className="h-7 w-7 rounded-full bg-slate-800 text-white flex items-center justify-center text-[11px] font-medium">
                {(auth.username || "Admin").slice(0, 2).toUpperCase()}
              </div>
              <ChevronDown size={14} className="text-slate-400" />
            </div>
          </div>
        </header>

        {/* Maintenance mode banner */}
        {maintenance.enabled && (
          <div className="flex items-center justify-between gap-3 px-4 sm:px-6 py-2.5 text-xs sm:text-sm" style={{ background: `${BRAND.danger}12`, color: BRAND.danger }}>
            <div className="flex items-center gap-2 min-w-0">
              <AlertTriangle size={14} className="shrink-0" />
              <span className="truncate">
                Maintenance Mode is <strong>ON</strong> — {maintenance.adminOnly ? "regular users are locked out; admins keep full access." : "shown to users, admin-only lockout is off."}
              </span>
            </div>
            <div className="flex items-center gap-2 shrink-0">
              <button
                onClick={() => setPreviewAsUser(true)}
                className="hidden sm:flex items-center gap-1 rounded-lg border px-2.5 py-1 text-[11px] font-medium hover:bg-rose-100/50"
                style={{ borderColor: `${BRAND.danger}40` }}
              >
                <Eye size={12} /> Preview
              </button>
              <button
                onClick={() => setActive("settings")}
                className="rounded-lg px-2.5 py-1 text-[11px] font-medium text-white"
                style={{ background: BRAND.danger }}
              >
                Manage
              </button>
            </div>
          </div>
        )}

        {/* Content */}
        <main className="p-4 sm:p-6">
          {active === "dashboard" ? (
            <DashboardPage onQuickAction={handleQuickAction} />
          ) : active === "users" ? (
            <UsersPage />
          ) : active === "wallet" ? (
            <WalletManagementPage />
          ) : active === "referrals" ? (
            <ReferralManagementPage />
          ) : active === "transactions" ? (
            <TransactionsPage />
          ) : active === "airtime2cash" ? (
            <AirtimeToCashPage />
          ) : active === "data" ? (
            <DataSettingsPage />
          ) : active === "airtime" ? (
            <AirtimeSettingsPage />
          ) : active === "notifications" ? (
            <NotificationsPage />
          ) : active === "settings" ? (
            <SettingsPage
              maintenance={maintenance}
              setMaintenance={setMaintenance}
              onPreviewMaintenance={() => setPreviewAsUser(true)}
            />
          ) : active === "paymentgateway" ? (
            <PaymentGatewaySection />
          ) : active === "reports" ? (
            <ReportsPage />
          ) : (
            <StubPage label={activeItem.label} Icon={activeItem.icon} />
          )}
        </main>
      </div>

      {/* Quick action modals */}
      <Modal open={modal === "fund"} onClose={() => setModal(null)} title="Fund Wallet">
        <Field label="User email or ID" placeholder="user@pancity.ng" />
        <Field label="Amount (₦)" type="number" placeholder="5000" />
        <button
          onClick={() => { setModal(null); showToast("Wallet funded successfully"); }}
          className="w-full rounded-lg py-2.5 text-sm font-medium text-slate-900 mt-1"
          style={{ background: BRAND.amber }}
        >
          Fund Wallet
        </button>
      </Modal>

      <Modal open={modal === "adduser"} onClose={() => setModal(null)} title="Add New User">
        <Field label="Full name" placeholder="Ada Obi" />
        <Field label="Email address" type="email" placeholder="ada@pancity.ng" />
        <Field label="Phone number" placeholder="080XXXXXXXX" />
        <button
          onClick={() => { setModal(null); showToast("User added successfully"); }}
          className="w-full rounded-lg py-2.5 text-sm font-medium text-slate-900 mt-1"
          style={{ background: BRAND.amber }}
        >
          <span className="inline-flex items-center gap-1.5"><Plus size={14} /> Create User</span>
        </button>
      </Modal>

      <Modal open={modal === "broadcast"} onClose={() => setModal(null)} title="Send Broadcast">
        <label className="block mb-3">
          <span className="block text-xs font-medium text-slate-600 mb-1">Message</span>
          <textarea rows={4} placeholder="Write an announcement for all users…"
            className="w-full rounded-lg border border-slate-200 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-400/40 focus:border-blue-400" />
        </label>
        <button
          onClick={() => { setModal(null); showToast("Broadcast queued for delivery"); }}
          className="w-full rounded-lg py-2.5 text-sm font-medium text-slate-900 mt-1"
          style={{ background: BRAND.amber }}
        >
          <span className="inline-flex items-center gap-1.5"><Send size={14} /> Send to all users</span>
        </button>
      </Modal>

      <Modal open={modal === "report"} onClose={() => setModal(null)} title="Generate Report">
        <label className="block mb-3">
          <span className="block text-xs font-medium text-slate-600 mb-1">Report type</span>
          <select className="w-full rounded-lg border border-slate-200 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-400/40">
            <option>Revenue Summary</option>
            <option>Transaction Log</option>
            <option>User Growth</option>
            <option>Network Sales</option>
          </select>
        </label>
        <div className="grid grid-cols-2 gap-3 mb-1">
          <Field label="From" type="date" />
          <Field label="To" type="date" />
        </div>
        <button
          onClick={() => { setModal(null); showToast("Report is being generated"); }}
          className="w-full rounded-lg py-2.5 text-sm font-medium text-slate-900 mt-2"
          style={{ background: BRAND.amber }}
        >
          <span className="inline-flex items-center gap-1.5"><FileText size={14} /> Generate</span>
        </button>
      </Modal>

      {/* Toast */}
      {toast && (
        <div className="fixed bottom-5 left-1/2 -translate-x-1/2 z-[60] rounded-xl bg-slate-900 text-white text-sm px-4 py-2.5 shadow-lg flex items-center gap-2 animate-[fadeIn_.15s_ease-out]">
          <CheckCircle2 size={15} className="text-emerald-400" />
          {toast}
        </div>
      )}
    </div>
  );
}
